import React from "react";
import styles from "./DateRangePicker.module.css";

export interface DateRangePickerProps {
  /** Field label */
  label?: string;
  value?: string;
  placeholder?: string;
  disabled?: boolean;
  required?: boolean;
  /** Validation error message */
  error?: string;
  onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onBlur?: (event: React.FocusEvent<HTMLInputElement>) => void;
}

/**
 * Start/end date range
 * @generated by Component Forge — edit schema and re-run forge generate
 */
export function DateRangePicker({ label, value = "", placeholder = "", disabled = false, required = false, error, onChange, onBlur }: DateRangePickerProps) {

  const inputId = React.useId();
  const errorId = `${inputId}-error`;
  return (
    <div className={styles.wrapper} data-testid="date-range-picker">
      <label className={styles.label} htmlFor={inputId}>
        {label}
      </label>
      <input
        id={inputId}
        type="text"
        className={[styles.root].filter(Boolean).join(" ")}
        placeholder={placeholder}
        defaultValue={value}
        disabled={disabled}
        required={required}
        aria-required={required || undefined}
        onChange={onChange}
        onBlur={onBlur}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? errorId : undefined}
      />
      {error && (
        <span id={errorId} className={styles.error} role="alert">
          {error}
        </span>
      )}
    </div>
  );
}

DateRangePicker.displayName = "DateRangePicker";
